async function main() {
  console.log(`Seeding ${INSTITUTIONS.length} institutions...`);
  let created = 0;
  for (const inst of INSTITUTIONS) {
    await prisma.institution.upsert({
      where: { uic: inst.uic },
      update: { name: inst.name, classes: inst.classes },
      create: { name: inst.name, uic: inst.uic, classes: inst.classes },
    });
    created++;
  }
  console.log(`Done. ${created} institutions seeded.`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());